import React from "react";
import useSplitPaymentStore from "../useSplitPaymentStore";
import useCalculateSchedule from "../hooks/useCalculateSchedule";

function PlanScheduleItem({ item }) {
    if (item) {
        const { dueDate, dueAmt } = item
        return (<div>
            <div>{dueDate}</div>
            <div>{dueAmt}</div>
        </div>)
    }
}

function PlanSchedule() {
    const { activePlan, totalAmount } = useSplitPaymentStore((s) => s)
    const { planSchedule } = useCalculateSchedule(activePlan, totalAmount)
    if (planSchedule && planSchedule.length > 0) {
        return (
            planSchedule.map((item) => {
                <PlanScheduleItem key={item.id} item={item} />
            })
        )
    }
}

export default PlanSchedule
